#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>

#include <cuda.h>

#define pin_stats_reset()   startCycle()
#define pin_stats_pause(cycles)   stopCycle(cycles)
#define pin_stats_dump(cycles)    printf("timer: %Lu\n", cycles)

#define BENCH_PRINT

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9

// Timer functions from timer.h inlined here
#include <unistd.h>
#include <stdint.h>
#include <stdlib.h>

__inline__ uint64_t rdtsc() 
{
    uint32_t lo, hi;
    __asm__ __volatile__ ("rdtsc" : "=a" (lo), "=d" (hi));
    return (uint64_t)hi << 32 | lo;
}

unsigned long long start_cycles;
#define startCycle() (start_cycles = rdtsc())
#define stopCycle(cycles) (cycles = rdtsc()-start_cycles)

void
init(int argc, char** argv)
{
	if(3 == argc){
		cols = atoi(argv[1]);
		rows = atoi(argv[2]);
	}else{
                printf("Usage: pathfiner width num_of_steps\n");
                exit(0);
        }
	data = new int[rows*cols];
	wall = new int*[rows];
	for(int n=0; rows > n; n++)
		wall[n]=data+cols*n;
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; rows > i; i++)
    {
        for (int j = 0; cols > j; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
    for (int j = 0; cols > j; j++)
        result[j] = wall[0][j];
#ifdef BENCH_PRINT
    for (int i = 0; rows > i; i++)
    {
        for (int j = 0; cols > j; j++)
        {
            printf("%d ",wall[i][j]) ;
        }
        printf("\n") ;
    }
#endif
}

void 
fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);

}

#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

// CUDA kernel for the main computation
__global__ void pathfinder_step(const int* src, int* dst, const int* wall_row, int cols) {
    int n = blockIdx.x * blockDim.x + threadIdx.x;
    if (n < cols) {
        int min_val = src[n];
        if (n > 0)
            min_val = min(min_val, src[n - 1]);
        if (n < cols - 1)
            min_val = min(min_val, src[n + 1]);
        dst[n] = wall_row[n] + min_val;
    }
}

void run(int argc, char** argv);

int main(int argc, char** argv)
{
    run(argc,argv);

    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    unsigned long long cycles;

    int *src, *dst, *temp;

    dst = result;
    src = new int[cols];

    pin_stats_reset();

    // Allocate device memory
    int *d_src, *d_dst, *d_wall;
    cudaMalloc((void**)&d_src, cols * sizeof(int));
    cudaMalloc((void**)&d_dst, cols * sizeof(int));
    cudaMalloc((void**)&d_wall, rows * cols * sizeof(int));

    // Copy wall data to device
    cudaMemcpy(d_wall, data, rows * cols * sizeof(int), cudaMemcpyHostToDevice);

    // Copy initial src data (result) to device d_src
    cudaMemcpy(d_src, dst, cols * sizeof(int), cudaMemcpyHostToDevice);

    int threadsPerBlock = 256;
    int blocksPerGrid = (cols + threadsPerBlock - 1) / threadsPerBlock;

    for (int t = 0; t < rows - 1; t++) {
        // Launch kernel for row t+1
        pathfinder_step<<<blocksPerGrid, threadsPerBlock>>>(d_src, d_dst, d_wall + (t + 1) * cols, cols);
        cudaDeviceSynchronize();

        // Swap pointers
        temp = src;
        src = dst;
        dst = temp;

        // Swap device pointers accordingly
        int* d_temp = d_src;
        d_src = d_dst;
        d_dst = d_temp;
    }

    // Copy final result back to host
    cudaMemcpy(dst, d_src, cols * sizeof(int), cudaMemcpyDeviceToHost);

    pin_stats_pause(cycles);
    pin_stats_dump(cycles);

#ifdef BENCH_PRINT

    for (int i = 0; cols > i; i++)

            printf("%d ",data[i]) ;

    printf("\n") ;

    for (int i = 0; cols > i; i++)

            printf("%d ",dst[i]) ;

    printf("\n") ;

#endif

    delete [] data;
    delete [] wall;
    delete [] dst;
    delete [] src;

    cudaFree(d_src);
    cudaFree(d_dst);
    cudaFree(d_wall);
}
